#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int dfs(int node, int* values, int** edges, int* edgesCount, int* maxSum) {
    int sum = values[node];
    for (int i = 0; i < edgesCount[node]; i++) {
        int child = edges[node][i];
        sum += dfs(child, values, edges, edgesCount, maxSum);
    }
    *maxSum = max(*maxSum, sum);
    return sum;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* values = (int*) malloc(N * sizeof(int));
        int** edges = (int**) malloc(N * sizeof(int*));
        int* edgesCount = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            edges[i] = (int*) malloc(N * sizeof(int));
            edgesCount[i] = 0;
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            edges[u][edgesCount[u]++] = v;
            edges[v][edgesCount[v]++] = u;
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &values[i]);
        }
        int maxSum = -1;
        dfs(0, values, edges, edgesCount, &maxSum);
        printf("%d\n", maxSum);
        for (int i = 0; i < N; i++) {
            free(edges[i]);
        }
        free(edges);
        free(edgesCount);
        free(values);
    }
    return 0;
}

