import java.util.Scanner;
public class Main {
    public static int max(int a, int b) { return a > b ? a : b; }
    public static int dfs(int node, int[] values, int[][] edges, int[] maxSum) {
        int sum = values[node];
        for (int child : edges[node]) {
            sum += dfs(child, values, edges, maxSum);
        }
        maxSum[0] = max(maxSum[0], sum);
        return sum;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] values = new int[N];
            int[][] edges = new int[N][];
            for (int i = 0; i < N; i++) {
                edges[i] = new int[0];
            }
            for (int i = 0; i < N - 1; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                int[] newEdgesU = new int[edges[u].length + 1];
                System.arraycopy(edges[u], 0, newEdgesU, 0, edges[u].length);
                newEdgesU[edges[u].length] = v;
                edges[u] = newEdgesU;
                int[] newEdgesV = new int[edges[v].length + 1];
                System.arraycopy(edges[v], 0, newEdgesV, 0, edges[v].length);
                newEdgesV[edges[v].length] = u;
                edges[v] = newEdgesV;
            }
            for (int i = 0; i < N; i++) {
                values[i] = scanner.nextInt();
            }
            int[] maxSum = new int[] {-1};
            dfs(0, values, edges, maxSum);
            System.out.println(maxSum[0]);
        }
    }
}

